#!/usr/bin/env node
// Generated by Meshly Build Station — do not edit by hand. FAILS OPEN.
import { getActiveTask } from "./meshly-hooks-lib.mjs";
import { fileURLToPath } from "node:url";
import { dirname, resolve, relative, isAbsolute } from "node:path";

const HERE = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(HERE, "..", "..");

const ALLOW = JSON.stringify({
  hookSpecificOutput: { hookEventName: "PreToolUse", permissionDecision: "allow" },
});
function deny(reason) {
  return JSON.stringify({
    hookSpecificOutput: {
      hookEventName: "PreToolUse",
      permissionDecision: "deny",
      permissionDecisionReason: reason,
    },
  });
}
async function readStdin() {
  let b = "";
  for await (const c of process.stdin) b += c;
  return b;
}
// Exempt edits outside the repo (e.g. plan files) and `.claude/` meta files.
function exempt(filePath) {
  if (!filePath) return true;
  const abs = isAbsolute(filePath) ? filePath : resolve(ROOT, filePath);
  const rel = relative(ROOT, abs).replace(/\\/g, "/");
  if (rel === "" || rel === ".." || rel.startsWith("../") || isAbsolute(rel)) return true;
  if (rel === ".claude" || rel.startsWith(".claude/")) return true;
  return false;
}

try {
  const raw = await readStdin();
  const input = raw ? JSON.parse(raw) : null;
  const ti = (input && input.tool_input) || {};
  const filePath = ti.file_path || ti.notebook_path || "";
  if (exempt(filePath)) {
    process.stdout.write(ALLOW);
  } else {
    const active = await getActiveTask();
    if (!active || active.has_active) {
      process.stdout.write(ALLOW);
    } else {
      process.stdout.write(
        deny(
          "No in-progress Meshly Build task in this project. Start one first: " +
          "mcp__meshly-build__create_task -> move_task('To Do') -> start_task, " +
          "then retry the edit. (Edits under .claude/ or outside the repo are exempt.)"
        )
      );
    }
  }
} catch {
  process.stdout.write(ALLOW);
}
